const files = $input.first().json.files || [];
const validFiles = files.filter(function(f) { return f.fileName && f.filePath; });
if (validFiles.length === 0) return [];
return validFiles.map(function(f) {
  return { json: { fileName: f.fileName, filePath: f.filePath } };
});

const fileData = $input.first().json;
if (fileData.skip || !fileData.fileName) return [];
const fileName = fileData.fileName || '';
const filePath = fileData.filePath || '';
const content = fileData.content || '';

const lines = content.split('\n').map(function(l) { return l.trim(); }).filter(function(l) { return l.length > 0; });
const urls = lines.filter(function(l) { return l.startsWith('http://') || l.startsWith('https://'); });

if (urls.length === 0) return [];

const baseName = fileName.replace(/\.(txt|url|md)$/i, '').replace(/[_\-]/g, ' ').trim();

return urls.map(function(url, i) {
  return { json: {
    url: url,
    sourceTitle: baseName,
    fileName: fileName,
    filePath: filePath,
    urlIndex: i + 1,
    urlTotal: urls.length
  }};
});

const d = $input.first().json;
if (!d.url || !d.url.startsWith('http')) return [];
const url = d.url;
let type = 'webpage';
if (url.indexOf('youtube.com') !== -1 || url.indexOf('youtu.be') !== -1) type = 'youtube';
else if (url.indexOf('twitter.com') !== -1 || url.indexOf('x.com') !== -1) type = 'twitter';
else if (url.indexOf('linkedin.com') !== -1) type = 'linkedin';
else if (url.indexOf('facebook.com') !== -1) type = 'facebook';
else if (url.indexOf('instagram.com') !== -1) type = 'instagram';
else if (url.indexOf('tiktok.com') !== -1) type = 'tiktok';
else if (url.indexOf('reddit.com') !== -1) type = 'reddit';
else if (/\.(mp3|wav|ogg|aac)$/i.test(url)) type = 'audio';
else if (/\.(mp4|avi|mov|mkv)$/i.test(url)) type = 'video';
else if (/\.pdf$/i.test(url)) type = 'pdf';
const ts = new Date().toISOString().replace(/[:.]/g, '-').slice(0, 19);
return [{ json: Object.assign({}, d, { type: type, timestamp: ts }) }];

const typeData = $('🔍 تحديد نوع الرابط').first().json;
const jinaData = $input.first().json;
let rawContent = jinaData.body || jinaData.data || '';

// ── فحص: هل أعادت Jina صفحتها الرئيسية بدلاً من المحتوى؟
const isJinaHomepage = rawContent.includes('r.jina.ai/YOUR_URL') || rawContent.includes('s.jina.ai/YOUR_SEARCH') || rawContent.includes('[Balance left]');
if (isJinaHomepage || rawContent.trim().length < 100) {
  // المحتوى غير صالح — نتخطى هذا الرابط
  return [{ json: Object.assign({}, typeData, { skip: true, skipReason: 'محتوى Jina غير صالح أو الرابط مكسور' }) }];
}

// ── استخراج العنوان الحقيقي من المحتوى (أول H1 أو H2)
let pageTitle = typeData.sourceTitle || typeData.url;
const h1Match = rawContent.match(/^#\s+(.+)$/m);
const h2Match = rawContent.match(/^##\s+(.+)$/m);
if (h1Match) pageTitle = h1Match[1].trim();
else if (h2Match) pageTitle = h2Match[1].trim();
// تنظيف العنوان من رموز Markdown
pageTitle = pageTitle.replace(/[\[\]\(\)\*\_\`]/g, '').trim().slice(0, 100);

// ── تنظيف المحتوى حسب النوع
let cleanContent = rawContent;
if (typeData.type === 'tiktok') {
  const lines = rawContent.split('\n');
  const relevantLines = [];
  let foundDescription = false;
  for (let i = 0; i < lines.length; i++) {
    const line = lines[i].trim();
    if (!foundDescription && (line === '' || line === 'Log in' || line === 'Search' ||
        line === 'For You' || line === 'Shop' || line === 'Explore' ||
        line === 'Following' || line === 'LIVE' || line === 'Upload' ||
        line === 'Profile' || line === 'More' || line.startsWith('©'))) continue;
    if (!foundDescription && line.length > 10 && !line.startsWith('[![') && !line.startsWith('[**')) foundDescription = true;
    if (foundDescription) {
      if (line === 'Comments' || line === 'You may like' || line === 'Log in' ||
          line.startsWith('Introducing keyboard') || line.startsWith('Go to previous')) break;
      if (line.startsWith('[![') || (line.startsWith('[') && line.includes('ago'))) continue;
      if (line.length > 0) relevantLines.push(line);
    }
  }
  cleanContent = relevantLines.join('\n').trim();
  if (cleanContent.length < 50) cleanContent = rawContent.slice(0, 2000);
} else if (typeData.type === 'youtube') {
  const descMatch = rawContent.match(/Description[:\s]+([\s\S]{0,1500})/);
  cleanContent = descMatch ? descMatch[1].trim() : rawContent.slice(0, 3000);
} else {
  cleanContent = rawContent.slice(0, 4000);
}

// ── بناء البرومبت بدون طلب code block
const prompt = 'أنت مساعد متخصص في تلخيص المحتوى الرقمي باللغة العربية.\n\nالمصدر: ' + typeData.url + '\nالنوع: ' + typeData.type + '\n\nاكتب تقريراً منظماً يحتوي على:\n\n## الملخص\n(3-5 جمل تلخص المحتوى الرئيسي)\n\n## النقاط الرئيسية\n(5 نقاط مرقمة)\n\n## الكلمات المفتاحية\n(5 كلمات أو عبارات مفتاحية)\n\nالمحتوى للتلخيص:\n' + cleanContent.slice(0, 3000) + '\n\nأجب مباشرة بالعربية بدون مقدمات.';

return [{ json: Object.assign({}, typeData, { prompt: prompt, jinaContent: cleanContent, pageTitle: pageTitle }) }];

// تخطي الروابط غير الصالحة
const d = $input.first().json;
if (d.skip) return [];
return [$input.first()];

const prepData = $('🧠 تجهيز البرومبت').first().json;
const aiData = $input.first().json;
const content = prepData.jinaContent || '';
const summary = aiData.response || '';
// إزالة أي code block من الملخص إن وُجد
const cleanSummary = summary.replace(/^```[\w]*\n?/gm, '').replace(/^```\s*$/gm, '').trim();
const wordCount = content.split(/\s+/).filter(function(w) { return w.length > 0; }).length;
const dateStr = new Date().toLocaleDateString('ar-SA');

const fileName = prepData.fileName || '';
const filePath = prepData.filePath || ('/data/url_inbox/' + fileName);
const ts = prepData.timestamp || new Date().toISOString().replace(/[:.]/g, '-').slice(0, 19);

// العنوان: من الصفحة الفعلية أولاً، ثم من اسم الملف
const pageTitle = prepData.pageTitle || prepData.sourceTitle || prepData.url;
const safe = pageTitle.replace(/[^\u0600-\u06FFa-zA-Z0-9 ]/g, '').trim().slice(0, 60).replace(/\s+/g, '_');
const outputFilename = ts + '_' + safe + '.md';

const urlInfo = prepData.urlTotal > 1 ? '\n**الرابط:** ' + prepData.urlIndex + ' من ' + prepData.urlTotal : '';

const md = '---\ntitle: "' + pageTitle + '"\nurl: ' + prepData.url + '\ntype: ' + prepData.type + '\ndate: ' + ts + '\nwords: ' + wordCount + '\nsource_file: ' + fileName + '\n---\n\n# ' + pageTitle + '\n\n**المصدر:** ' + prepData.url + '  \n**النوع:** ' + prepData.type + '  \n**التاريخ:** ' + dateStr + urlInfo + '  \n**الملف الأصلي:** ' + fileName + '\n\n---\n\n' + cleanSummary + '\n\n---\n\n## المحتوى الكامل\n\n' + content + '\n';

return [{ json: {
  markdown: md,
  outputFilename: outputFilename,
  fileName: fileName,
  filePath: filePath,
  wordCount: wordCount,
  url: prepData.url,
  type: prepData.type,
  title: pageTitle,
  urlIndex: prepData.urlIndex,
  urlTotal: prepData.urlTotal,
  timestamp: ts
} }];

const mdData = $('📝 بناء Markdown').first().json;
const isLastUrl = mdData.urlIndex === mdData.urlTotal;
const fileName = mdData.fileName || '';
const filePath = mdData.filePath || ('/data/url_inbox/' + fileName);

if (!isLastUrl) {
  return [{ json: {
    readyToMove: false,
    fileName: fileName,
    filePath: filePath,
    outputFilename: mdData.outputFilename,
    urlIndex: mdData.urlIndex,
    urlTotal: mdData.urlTotal
  } }];
}

return [{ json: {
  readyToMove: true,
  fileName: fileName,
  filePath: filePath,
  outputFilename: mdData.outputFilename,
  urlIndex: mdData.urlIndex,
  urlTotal: mdData.urlTotal,
  url: mdData.url,
  type: mdData.type,
  wordCount: mdData.wordCount
} }];

const data = $input.first().json;
return [{ json: {
  success: true,
  sourceFile: data.fileName || data.moved_from || 'unknown',
  outputFile: data.outputFilename || '',
  url: data.url || '',
  type: data.type || '',
  words: data.wordCount || 0,
  urlIndex: data.urlIndex,
  urlTotal: data.urlTotal,
  timestamp: new Date().toISOString()
} }];
